import os

def compare_files(file1_path, file2_path, chunk_size=4096):
    if not os.path.exists(file1_path) or not os.path.exists(file2_path):
        raise FileNotFoundError("Both files must exist.")

    if os.path.samefile(file1_path, file2_path):
        return True

    with open(file1_path, 'rb') as f1, open(file2_path, 'rb') as f2:
        while True:
            chunk1 = f1.read(chunk_size)
            chunk2 = f2.read(chunk_size)

            if chunk1 != chunk2:
                return False

            if not chunk1:  # Both chunks are empty, files are identical
                return True
